/**
 * Blob Utils
 * Base64 and file utility functions for React Native
 */
/**
 * Extract raw base64 from data URI
 */
export declare function extractBase64FromDataUri(dataUri: string): string;
/**
 * Detect MIME type from data URI or base64
 */
export declare function detectMimeType(base64: string): string;
/**
 * Get file extension from MIME type
 */
export declare function getExtensionFromMimeType(mimeType: string): string;
/**
 * Write base64 to a temp file and return the file URI
 * This is React Native compatible (no Blob/ArrayBuffer needed)
 */
export declare function base64ToTempFile(base64: string, filename?: string): Promise<string>;
/**
 * Delete a temp file
 */
export declare function deleteTempFile(uri: string): Promise<void>;
/**
 * Get file size from URI
 */
export declare function getFileSize(uri: string): number;
